      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const tasksService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Task name is required');
  }

  const task = tasksService.addTask(req.projectId, { name });
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const status = req.query.status;
  const tasks = tasksService.getTasks(req.projectId, status);
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }

  const task = tasksService.updateTask(req.projectId, taskId, { status });
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }

  res.json({ task });
});

module.exports = router;
