      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');

let projects = {};

function addTask(projectId, task) {
  if (!projects[projectId]) {
    projects[projectId] = [];
  }

  const newTask = { ...task, id: randomUUID(), status: 'todo' };
  projects[projectId].push(newTask);
  return newTask;
}

function getTasks(projectId, status) {
  if (!projects[projectId]) {
    return [];
  }

  let tasks = projects[projectId];
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

function updateTask(projectId, taskId, updates) {
  const projectTasks = projects[projectId] || [];
  const taskIndex = projectTasks.findIndex(task => task.id === taskId);

  if (taskIndex === -1) {
    return null;
  }

  const updatedTask = { ...projectTasks[taskIndex], ...updates };
  projects[projectId][taskIndex] = updatedTask;
  return updatedTask;
}

module.exports = {
  addTask,
  getTasks,
  updateTask,
};
